import numpy as npimport matplotlib.pyplot as pltfrom matplotlib.animation import FuncAnimation# =========================================================================# 1. PHYSICAL & SIMULATION PARAMETERS# =========================================================================g = 9.8      # Acceleration due to gravity (m/s^2)L = 1.0      # Length of the pendulum rod (m)dt = 0.01    # Time step size for numerical integration (s)tf = 10.0    # Total simulation time span (s)# Initial dynamic states: [Angular displacement (rad), Angular velocity (rad/s)]theta0 = np.radians(20)  # Convert 20 degrees initial amplitude to radiansomega0 = 0.0             # Released from rest# =========================================================================# 2. GOVERNING DIFFERENTIAL EQUATIONS (State-Space Representation)# Converts the 2nd-order non-linear ODE into a system of two 1st-order ODEs:# dy[0]/dt = omega# dy[1]/dt = -(g/L) * sin(theta)# =========================================================================def derivatives(y):    theta = y[0]    omega = y[1]    return np.array([omega, - (g / L) * np.sin(theta)])# =========================================================================# 3. 4TH-ORDER RUNGE-KUTTA (RK4) NUMERICAL INTEGRATOR# Explicit multi-step method solving ODEs with a local error of O(dt^5)# =========================================================================def runge_kutta(y0):    t = np.arange(0, tf, dt)    y = np.zeros((len(t), 2))    y[0] = y0  # Set initial state boundary conditions        for i in range(1, len(t)):        # Compute the four RK4 increments (slopes)        k1 = dt * derivatives(y[i-1])        k2 = dt * derivatives(y[i-1] + 0.5 * k1)        k3 = dt * derivatives(y[i-1] + 0.5 * k2)        k4 = dt * derivatives(y[i-1] + k3)                # Compute next state using a weighted average of increments        y[i] = y[i-1] + (k1 + 2*k2 + 2*k3 + k4) / 6.0            return t, y# Execute solver to obtain time-series state trajectoriest, y = runge_kutta([theta0, omega0])# Transform angular state (theta) into Cartesian coordinates (X, Y) for kinematic renderingx = L * np.sin(y[:, 0])y_position = -L * np.cos(y[:, 0])# =========================================================================# 4. ANIMATION AND GRAPHICAL USER INTERFACE SETUP# =========================================================================fig, ax = plt.subplots(figsize=(6, 6))ax.set_xlim(-L - 0.2, L + 0.2)ax.set_ylim(-L - 0.2, 0.2)ax.set_aspect('equal')  # Enforce 1:1 aspect ratio to prevent geometric distortionax.grid(True, linestyle='--', alpha=0.5)ax.set_title("Non-Linear Pendulum Dynamics (RK4 Simulation)", fontsize=11, fontweight='bold')ax.set_xlabel("X Position (m)")ax.set_ylabel("Y Position (m)")# Initialize the plot element: 'ro-' defines a red rod with a circular bobline, = ax.plot([], [], 'ro-', lw=2, markersize=8)  # Sequential frame update function for the animation enginedef update(frame):    # Map the line from origin (0,0) to current Cartesian coordinates    line.set_data([0, x[frame]], [0, y_position[frame]])    return line,# Calculate appropriate FPS (Frames Per Second) matching the physical clock time stepfps = int(1 / dt)# Generate the dynamic animation handleani = FuncAnimation(fig, update, frames=len(t), interval=dt*1000, blit=True, repeat=True)# =========================================================================# 5. ANIMATION EXPORT ROUTINE (GIF Generation)# Saves the simulation frame sequences using the Pillow engine# =========================================================================output_filename = "pendulum_simulation.gif"print(f"[System] Exporting animation sequences to '{output_filename}'... Please wait.")# Note: Using identical FPS to ensure the exported GIF plays back at real physical speedani.save(output_filename, writer='pillow', fps=fps)print("[System] Export complete. GIF file successfully generated.")plt.show()